# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector as mysql
from getpass import getpass

def main():
    print("MySQL LOAD DATA INFILE script")
    
    # Credentials
    user = input("Enter your MySQL username: ")
    password = getpass("Enter your MySQL password: ")
    database = input("Enter the name of the database you want to import into: ")
    table_name = input("Enter the name of the target table for bulk loading: ")
    
    # File path from user input
    file_path = input("Please provide the file path for bulk load: ")

    conn = mysql.connect(user=user, password=password, database=database)
    cursor = conn.cursor()

    try:
        cursor.execute('SET GLOBAL local_infile=1') # enable local infile
        
        qry = "LOAD DATA INFILE '{}' INTO TABLE {} FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\n' IGNORE 1 ROWS".format(file_path, table_name)
        cursor.execute(qry)
        
    except mysql.Error as err:
        print("Something went wrong: {}".format(err))
    
    finally:
        conn.close()

if __name__ == "__main__":
    main()